import{_ as o,o as e,c as a,a2 as r}from"./chunks/framework.gSjTt1Hm.js";const u=JSON.parse('{"title":"Proxy Pool","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/proxy.md","filePath":"en/guide/proxy.md","lastUpdated":1783864095000}'),i={name:"en/guide/proxy.md"};function l(n,t,d,h,s,p){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="proxy-pool" tabindex="-1">Proxy Pool <a class="header-anchor" href="#proxy-pool" aria-label="Permalink to &quot;Proxy Pool&quot;">​</a></h1><h2 id="what-is-a-proxy-pool" tabindex="-1">What is a Proxy Pool <a class="header-anchor" href="#what-is-a-proxy-pool" aria-label="Permalink to &quot;What is a Proxy Pool&quot;">​</a></h2><p>A proxy pool is a collection of HTTP proxies used to access AI platforms. When direct access is restricted, requests can be forwarded through proxies.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Go to &quot;Proxy Pool&quot; to create pools, then &quot;Proxy Management&quot; to add proxies.</p><h3 id="pool-configuration" tabindex="-1">Pool Configuration <a class="header-anchor" href="#pool-configuration" aria-label="Permalink to &quot;Pool Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Name</td><td>Pool identifier</td></tr><tr><td>Enable</td><td>Whether to enable the pool</td></tr></tbody></table><h3 id="proxy-configuration" tabindex="-1">Proxy Configuration <a class="header-anchor" href="#proxy-configuration" aria-label="Permalink to &quot;Proxy Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Address</td><td>Proxy address: <code>http://user:pass@host:port</code></td></tr><tr><td>Pool</td><td>Which pool to bind to</td></tr><tr><td>Enable</td><td>Whether to enable the proxy</td></tr></tbody></table><h2 id="health-check" tabindex="-1">Health Check <a class="header-anchor" href="#health-check" aria-label="Permalink to &quot;Health Check&quot;">​</a></h2><p>FWP automatically monitors proxy health:</p><ul><li><strong>healthy</strong> — Fully available</li><li><strong>degraded</strong> — Performance reduced, used less frequently</li><li><strong>down</strong> — Unavailable, enters cooldown period</li></ul><h2 id="routing-strategy" tabindex="-1">Routing Strategy <a class="header-anchor" href="#routing-strategy" aria-label="Permalink to &quot;Routing Strategy&quot;">​</a></h2><ul><li>Prefers healthy proxies</li><li>Degraded proxies have 50% skip probability</li><li>Down proxies are completely skipped, auto-probed after cooldown</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2>',15)])])}const x=o(i,[["render",l]]);export{u as __pageData,x as default};
